import{_ as t,o as n,c as o,ae as a}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"Configure Events for Self-Attributing Networks","description":"","frontmatter":{"title":"Configure Events for Self-Attributing Networks","slug":"configuring-events-for-self-attributing-networks"},"headers":[],"relativePath":"marketer-hub/configuring-events-for-self-attributing-networks.md","filePath":"marketer-hub/configuring-events-for-self-attributing-networks.md"}'),i={name:"marketer-hub/configuring-events-for-self-attributing-networks.md"};function r(s,e,l,p,u,c){return n(),o("div",null,[...e[0]||(e[0]=[a('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>Explore Branch’s new linking experience for <a href="https://help.branch.io/docs/create-web-links-1#view-and-manage-links" target="_blank" rel="noreferrer">Web Links</a> and <a href="https://help.branch.io/docs/create-app-links-new" target="_blank" rel="noreferrer">App Links</a>, which offer deep linking, flexible configuration, and link analysis across multiple platforms!</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch accepts different naming conventions for the conversion events we measure. For example, maybe the app Modern Clothing Styles sends a custom event called “Check Out&quot;. Most people who see this name would understand what it means. If they sent it as “PURCHASE” it wouldn’t be the same event, nor would it be clear.</p><p>However, Self-Attributing Networks (SANs) such as Facebook do not allow customers to optimize against custom events or show custom events in their UI. Therefore, if you want Facebook to auto-optimize against your RiderFirstBooking event, you’ll need to send it to Facebook as a “fb_mobile_purchase” event.</p><h2 id="supported-sans" tabindex="-1">Supported SANs <a class="header-anchor" href="#supported-sans" aria-label="Permalink to &quot;Supported SANs&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Event Mapping Support</p><p>The ability to configure event mappings is available only for integrations with SANs. For all other ad partners, Branch uses standard event mappings for Postbacks.</p></div><p>You can configure event mappings for the following Self-Attributing Networks:</p><ul><li><strong>Facebook</strong></li><li><strong>Google Ads (formerly Google AdWords)</strong></li><li><strong>Google Marketing Platform</strong></li><li><strong>Roku</strong></li><li><strong>Snap</strong></li><li><strong>Twitter</strong></li><li><strong>TikTok</strong></li></ul><div class="info custom-block"><p class="custom-block-title">Apple Ads Not Supported</p><p>Configuring event mappings for Apple Ads - although a SAN - is not supported due to the inability to send events server side.</p></div><h2 id="default-event-mappings" tabindex="-1">Default Event Mappings <a class="header-anchor" href="#default-event-mappings" aria-label="Permalink to &quot;Default Event Mappings&quot;">​</a></h2><p>Your events will be mapped by default to ad partner event names for the purposes of campaign optimization and reporting.</p><p>Please refer to the following respective documents for our default event mappings per SAN:</p><ul><li><a href="./facebook-ads-overview.html#event-names">Facebook</a></li><li><a href="./google-ads-data-reporting.html#event-mapping">Google Ads</a></li><li><a href="./google-marketing-platform.html#forward-events-to-gmp">Google Marketing Platform</a></li><li><a href="./roku.html#forwarding-events-to-roku">Roku</a></li><li><a href="./snap.html#event-names">Snap</a></li><li><a href="./twitter-ads.html#forwarding-events-to-twitter-ads">Twitter</a></li><li><a href="./tiktok-data-reporting.html#mapping-between-tiktok-branch">TikTok</a></li></ul><h2 id="configuring-event-mappings" tabindex="-1">Configuring Event Mappings <a class="header-anchor" href="#configuring-event-mappings" aria-label="Permalink to &quot;Configuring Event Mappings&quot;">​</a></h2><p>If you do not want to use the default event mappings, you can configure how Branch maps the events it tracks with those of the Self-Attributing Network.</p><p>To configure a SAN’s event mappings:</p><ol><li><p>In the left-hand navigation, under <strong>Ads</strong>, click <strong>Partner Management</strong>.</p></li><li><p>Find and select the SAN for which you want to configure the event mappings.</p></li><li><p>Click the <strong>Events Config</strong> tab.</p></li><li><p>Click the <strong>Add Event Mappings</strong> button.</p></li><li><p>Map your event by providing the following:</p><ol><li><strong>Your Event Name</strong> - The app event you want mapped; only app events you are tracking with the Branch SDK are available to be mapped.</li><li><strong>Your Customer Event Alias</strong> - Your custom name for your app event; only available if you’ve already implemented <code>customer_event_alias</code> in the Branch SDK.</li><li><strong>Ad Partner Event Name</strong> - The ad partner’s name for the app events they support; see default event mappings above.</li></ol></li><li><p>Click <strong>Save</strong>.</p></li></ol><div class="warning custom-block"><p class="custom-block-title">Disabling events</p><p>If you disable an event, you will not receive any attribution data for that event. If this is not your intention, rather rename the event to a custom name.</p></div><h2 id="using-custom-event-names" tabindex="-1">Using Custom event names <a class="header-anchor" href="#using-custom-event-names" aria-label="Permalink to &quot;Using Custom event names&quot;">​</a></h2><p>If you are using the self-attributing network&#39;s SDK to track in-app events but need Branch to collect attribution data for these events, you will need to map Branch events to custom names to prevent duplicates from being tracked on the network. To create custom events follow the steps below:</p><ol><li><p>Click on the pencil icon in the drop down next to value custom</p></li><li><p>Rename the custom event to your new event name</p></li><li><p>Save the name and don&#39;t forget to save your configuration when all of your events have been renamed</p></li></ol><p>If you would like to revert to the default name, you can just re-select the network&#39;s name from the dropdown.</p><h2 id="things-to-keep-in-mind" tabindex="-1">Things to Keep in Mind <a class="header-anchor" href="#things-to-keep-in-mind" aria-label="Permalink to &quot;Things to Keep in Mind&quot;">​</a></h2><ul><li><p>Branch defines an “event” as a combination of Your Event Name + Customer Event Alias.</p></li><li><p>You <strong>cannot</strong> use <a href="https://help.branch.io/developers-hub/docs/track-branch-events" target="_blank" rel="noreferrer">Branch Standard event names</a> as your custom event name. Doing so will result in your custom event not being tracked.</p></li><li><p>You <strong>cannot</strong> configure more than one of the same event; i.e. the same combination of event name and customer event alias.</p></li><li><p>You <strong>cannot</strong> map to a single Branch event to two different Ad Partner events.</p><ul><li>You <strong>can</strong> map two different Branch events to a single Ad Partner Event.</li></ul></li><li><p>You can only configure at the event level; sub-parameters (e.g. order_id or revenue) cannot be mapped to ad partner events.</p></li><li><p>If you start to measure a new app event after you’ve enabled the SAN integration, you must manually configure the event.</p></li><li><p>Some SANs accept custom events. For those that do, it’s indicated in the Ad Partner Event Name drop-down.</p></li><li><p>If you have not configured any event mappings, Branch will use the default mappings outlined above for all events.</p></li><li><p>If you have <strong>at least one event mapped, only the mapped events visible in the UI will be sent.</strong></p></li><li><p>When unchecked, the <strong>Enabled</strong> checkbox does not prevent events that the Branch SDK tracks automatically (for example, installs and opens) from being sent to ad networks. You must add <code>disableAdNetworkCallouts()</code> to your SDK integration to stop tracking these events.</p></li></ul>',24)])])}const h=t(i,[["render",r]]);export{d as __pageData,h as default};
